import os
import shutil
from core_lite.batch_ingestion.controller import BatchIngestionController

class MultimodalPipeline:
    def __init__(self):
        self.batch_controller = BatchIngestionController()

    def process_bundle(self, bundle_path):
        if bundle_path.endswith('.zip'):
            result = self.batch_controller.ingest(bundle_path)
            self.write_disposition_record(bundle_path, result)
            self.write_evidence_contribution(bundle_path, result)
            self.cleanup_incoming(bundle_path)
            return 0 if result == 'admitted' else 1
        else:
            # Existing logic for other input types
            pass

    def write_disposition_record(self, bundle_path, result):
        record_path = f'receipts/current/{os.path.basename(bundle_path)}.json'
        with open(record_path, 'w') as record_file:
            record_file.write(f'{{"bundle": "{bundle_path}", "result": "{result}"}}')

    def write_evidence_contribution(self, bundle_path, result):
        evidence_path = f'tracking/evidence_plane/{os.path.basename(bundle_path)}.json'
        with open(evidence_path, 'w') as evidence_file:
            evidence_file.write(f'{{"bundle": "{bundle_path}", "result": "{result}"}}')

    def cleanup_incoming(self, bundle_path):
        os.remove(bundle_path)

if __name__ == "__main__":
    pipeline = MultimodalPipeline()
    for bundle in os.listdir('incoming/'):
        bundle_path = os.path.join('incoming/', bundle)
        exit_code = pipeline.process_bundle(bundle_path)
        print(f'Processed {bundle_path} with exit code {exit_code}')
